<template>
    <div class="pa-5">
        <v-card>
            <v-card-actions>
                <v-spacer></v-spacer>
                <v-btn small color="primary" @click="subscription_dialog = true">New Subscription</v-btn>
            </v-card-actions>
            <v-data-table
                :headers="headers"
                :items="subscriptions"
                class="elevation-1"
                >
                <template v-slot:body = {items}>
                    <tbody>
                        <tr
                            v-for="item in items"
                            :key="item.id"
                        >
                            <td>{{ item.event_code }}</td>
                            <td>{{ item.start_date }}</td>
                            <td>{{ item.end_date }}</td>
                            <td>{{ item.theme }}</td>
                            <td>{{ item.hash_tag }}</td>
                            <td></td>
                            <td></td>
                            <td></td>
                            <td>{{ item.enable_message_approval == 1 ? 'Yes' : 'No' }}</td>
                            <td>
                                <v-btn x-small color="orange" dark 
                                    target="_blank"
                                    class="mr-2"
                                    :to="{name: 'ApprovedTestimonials', params : {id : item.subscription_key}}">
                                    Approved
                                </v-btn>
                                <v-btn x-small color="primary" 
                                    target="_blank"
                                    :to="{name: 'PendingTestimonials', params : {id : item.subscription_key}}">
                                    For Approval
                                </v-btn>
                            </td>
                            <td>
                                <v-btn x-small color="primary" text>Edit</v-btn>
                                <v-btn x-small color="error" text>Cancel</v-btn>
                            </td>
                            <td>
                                <v-btn x-small color="primary" @click="details = item; qr_code_dialog = true;">View</v-btn>
                            </td>
                        </tr>
                    </tbody>
                </template>
            </v-data-table>
        </v-card>
        <v-dialog v-model="subscription_dialog" width="500">
            <subscription-dialog @refresh="refreshData" @close="subscription_dialog = false"/>
        </v-dialog>
        <v-dialog v-model="qr_code_dialog" width="300">
            <v-card>
                <img :src="details.qr_code" width="300" >
            </v-card>
        </v-dialog>
    </div>
</template>
<script>
import SubscriptionDialog from '@/views/admin/dialog/SubscriptionDialog.vue';
import axios from 'axios';
export default {
    name : 'SubscriptionsView',
    components : {
        SubscriptionDialog
    },
    mounted() {
        this.refreshData();
    },
    methods: {
        refreshData() {
            axios({
                url : this.$store.state.api_url + '/subscriptions',
                method : 'GET',
                headers : {
                    Authorization : 'Bearer ' + this.$store.state.user.token
                }
            }).then(res => {
                this.subscriptions = res.data;
            });
        },
    },
    data() {
        return {
            details : {},
            qr_code_dialog : false,
            subscription_dialog : false,
            subscriptions : [],
            headers : [
                {
                    text : 'Event Code',
                    value : 'event_code',
                    sortable : true
                },
                {
                    text : 'Start Date',
                    value : 'start_date',
                    sortable : true
                },
                {
                    text : 'End Date',
                    value : 'end_date',
                    sortable : true
                },
                {
                    text : 'Theme',
                    value : 'theme',
                    sortable : false
                },
                {
                    text : 'Hashtag',
                    value : 'hashtag',
                    sortable : true
                },
                {
                    text : 'Wall Background',
                    value : 'background',
                    sortable : false
                },
                {
                    text : 'Banner',
                    value : 'banner',
                    sortable : false
                },
                {
                    text : 'Logo',
                    value : 'logo',
                    sortable : false
                },
                {
                    text : 'Requires Approval',
                    value : 'enable_message_approval'
                },
                {
                    text : 'Wall Posts',
                },
                {
                    text : 'Actions',
                },
                {
                    text : 'QR Code',
                }
            ]
        }
    }
}
</script>